// Script Continued Below
var ClientTaskTemplateHelpers = Class.create();
ClientTaskTemplateHelpers.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
	// STRY0085078 - TUP - Add Reviewer field on Template Instance - Controlled Organization Tasking Permissions
	getTemplateTopTaskerType: function(){
		var templateId = this.getParameter('templateId');
		var topTaskerTypeDiisplayValue = '';
		var grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');

		if(grTemp.get(templateId)){
			topTaskerTypeDiisplayValue = grTemp.getDisplayValue('u_tasker_type');
		}
		return topTaskerTypeDiisplayValue;
	},

	// STRY0076609 - check the sub tasks and the current task to see if they are review item types 
	checkForApprovalTypeOnTaskTempAndSubTaskTemp: function(){
		var taskTempId = this.getParameter('taskTempId');
		var isReviewTypeWithChildReviewtype = false;
		var grTaskTemp = new GlideRecordSecure('x_153465_discovert_route_tasks');
		if(grTaskTemp.get(taskTempId)){
			if(grTaskTemp.u_wait_for_subtasks_to_finish  && grTaskTemp.work_item_type == "review_item"){
				var grSubTaskTemps = new GlideRecordSecure('x_153465_discovert_route_tasks');
				grSubTaskTemps.addQuery('parent', taskTempId);
				grSubTaskTemps.addQuery('work_item_type', "review_item");
				grSubTaskTemps.query();
				while (grSubTaskTemps.next()){
					if(grSubTaskTemps.u_wait_for_subtasks_to_finish){
						isReviewTypeWithChildReviewtype = true;
						break;
					}
				}
			}
		}
		return isReviewTypeWithChildReviewtype;
	},


	// - STRY0075793 - Patch 2.5.13 allow start template and run template modals to be called from Native pages
	loadTemplateAndTaskIntoInstanceForm: function(){
		var fields = this.getParameter('fields');
		var templateId = this.getParameter('templateId');
		var parentTaskId = this.getParameter('parentTaskId');
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.loadTemplateAndTaskIntoInstanceForm(fields, templateId, parentTaskId));
	},

	// - STRY0075793 - Patch 2.5.13 allow start template and run template modals to be called from Native pages
	loadTemplateIntoInstanceForm: function(){
		var fields = this.getParameter('fields');
		var templateId = this.getParameter('templateId');
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.loadTemplateIntoInstanceForm(fields, templateId));
	},

	// STRY0079327 - get start template on task working on backend form
	createEmptyTemplateFieldsJSON: function(){
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.createEmptyTemplateFieldsJSON());
	},

	// STRY0079327 - get start template on task working on backend form
	loadTemplateInputsFromDataFields: function(){
		var fields = this.getParameter('fields');
		var oFileds = JSON.parse(fields);
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.loadTemplateInputsFromDataFields(oFileds));
	},

	// STRY0079327 - get start template on task working on backend form
	startTemplateWithID: function(){
		var templateInputs = this.getParameter('templateInputs');
		var oTemplateInputs = JSON.parse(templateInputs);
		var template = this.getParameter('template'); 
		var tTH = new TaskTemplateHelpers();
		return JSON.stringify(tTH.startTemplateWithID(template, true, oTemplateInputs));
	}

});
